const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('No data received from Google Sheets. Check the sheet ID and permissions.');
}

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const keys = Object.keys(row).filter(k => k !== 'row_number');
  const colA = keys[0];
  const colB = keys[1];
  const colC = keys.length > 2 ? keys[2] : null;

  if (colB && row[colB] && row[colB].toString().toLowerCase().trim() === 'pending') {
    const topic = row[colA].toString();
    const topicSlug = topic.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 60);

    return [{
      json: {
        topic,
        rowNumber: row.row_number || (i + 2),
        topicSlug,
        colA,
        colB,
        colC
      }
    }];
  }
}

throw new Error('No pending topics found in the Google Sheet.');

const text = $input.first().json.text;

if (!text) {
  throw new Error('No content received from Gemini. Check the AI model response.');
}

let cleanText = text.trim();
if (cleanText.startsWith('```')) {
  cleanText = cleanText.replace(/^```(?:md|markdown|mdx)?\n?/, '').replace(/\n?```$/, '');
}

// Defensive YAML frontmatter sanitizer:
// Ensures string values for title/titleAr/excerpt/excerptAr/coverImageAlt/category/categoryAr/author/authorAr
// are always wrapped in double quotes, even if Gemini forgot.
function quoteFrontmatterField(content, fieldName) {
  // Match: fieldName: <anything until end of line>
  // Skip if value already starts with a double quote
  const regex = new RegExp('^(' + fieldName + ':)[ \\t]*(.*)$', 'm');
  return content.replace(regex, function(match, key, value) {
    const trimmed = value.trim();
    if (!trimmed) return match;
    // Already properly quoted
    if (trimmed.startsWith('"') && trimmed.endsWith('"')) return match;
    // Strip wrapping single quotes if present
    let inner = trimmed;
    if (inner.startsWith("'") && inner.endsWith("'")) {
      inner = inner.slice(1, -1);
    }
    // Escape any internal double quotes
    inner = inner.replace(/\\"/g, '"').replace(/"/g, '\\"');
    return key + ' "' + inner + '"';
  });
}

// Split frontmatter from body to avoid touching content
const fmMatch = cleanText.match(/^(---\n)([\s\S]*?)(\n---)([\s\S]*)$/);
if (fmMatch) {
  let frontmatter = fmMatch[2];
  const fieldsToFix = ['title', 'titleAr', 'excerpt', 'excerptAr', 'coverImageAlt', 'category', 'categoryAr', 'author', 'authorAr'];
  for (const field of fieldsToFix) {
    frontmatter = quoteFrontmatterField(frontmatter, field);
  }
  cleanText = fmMatch[1] + frontmatter + fmMatch[3] + fmMatch[4];
}

// Extract the article title from the (now sanitized) frontmatter
let articleTitle = '';
const titleMatch = cleanText.match(/^title:\s*"([^"]*)"/m);
if (titleMatch) { articleTitle = titleMatch[1]; }

const topicData = $('Find First Pending Topic').first().json;

// Build a generic image search query from frontmatter tags (skip brand-y names)
const BRAND_BLOCKLIST = /airbnb|booking\.com|booking|accez|whatsapp|mada|sadad|ejar|gastat/i;
let searchQuery = 'hospitality business';
const tagsMatch = cleanText.match(/^tags:\s*\[([^\]]*)\]/m);
if (tagsMatch) {
  const rawTags = tagsMatch[1].split(',').map(t => t.trim().replace(/^["']|["']$/g, ''));
  const generic = rawTags.filter(t => t && !BRAND_BLOCKLIST.test(t));
  if (generic.length > 0) {
    searchQuery = generic.slice(0, 2).join(' ').toLowerCase();
  }
}

return [{
  json: {
    fileContent: cleanText,
    contentLength: cleanText.length,
    articleTitle: articleTitle || topicData.topic,
    searchQuery,
    topic: topicData.topic,
    topicSlug: topicData.topicSlug,
    rowNumber: topicData.rowNumber,
    colA: topicData.colA,
    colB: topicData.colB,
    colC: topicData.colC
  }
}];

const stripData = $('Strip Fences and Base64 Encode').first().json;
const unsplashResponse = $input.first().json;

let hasImage = false;
let imageUrl = '';
let coverImagePath = '/images/blog/pm-default.jpg';
let photographerName = '';
let photoUrl = '';

try {
  if (unsplashResponse && unsplashResponse.results && Array.isArray(unsplashResponse.results) && unsplashResponse.results.length > 0) {
    const firstResult = unsplashResponse.results[0];
    if (firstResult.urls && firstResult.urls.regular) {
      imageUrl = firstResult.urls.regular;
      coverImagePath = '/images/blog/' + stripData.topicSlug + '.jpg';
      hasImage = true;
      photographerName = (firstResult.user && firstResult.user.name) ? firstResult.user.name : '';
      photoUrl = (firstResult.links && firstResult.links.html) ? firstResult.links.html : '';
    }
  }
} catch (e) { hasImage = false; }

// Escape double quotes in photographer name for YAML safety
const escapedPhotographer = photographerName.replace(/"/g, '\\"');
const creditValue = photographerName ? ('Photo by ' + escapedPhotographer + ' on Unsplash') : '';

// Replace the coverImage line in the frontmatter
let updatedContent = stripData.fileContent;
const coverImageRegex = /coverImage:\s*"[^"]*"/;
if (coverImageRegex.test(updatedContent)) {
  updatedContent = updatedContent.replace(coverImageRegex, 'coverImage: "' + coverImagePath + '"');
}

// Inject coverImageCredit and coverImageCreditUrl after coverImageAlt (or after coverImage if alt not present)
if (hasImage && creditValue && photoUrl) {
  const creditBlock = 'coverImageCredit: "' + creditValue + '"\ncoverImageCreditUrl: "' + photoUrl + '"';
  // Remove any existing credit lines first to avoid duplicates on re-runs
  updatedContent = updatedContent.replace(/\n?coverImageCredit:\s*"[^"]*"/g, '');
  updatedContent = updatedContent.replace(/\n?coverImageCreditUrl:\s*"[^"]*"/g, '');
  // Insert after coverImageAlt line if it exists
  if (/coverImageAlt:\s*"[^"]*"/.test(updatedContent)) {
    updatedContent = updatedContent.replace(/(coverImageAlt:\s*"[^"]*")/, '$1\n' + creditBlock);
  } else {
    updatedContent = updatedContent.replace(/(coverImage:\s*"[^"]*")/, '$1\n' + creditBlock);
  }
}

return [{
  json: {
    fileContent: updatedContent,
    contentLength: updatedContent.length,
    articleTitle: stripData.articleTitle,
    topic: stripData.topic,
    topicSlug: stripData.topicSlug,
    rowNumber: stripData.rowNumber,
    colA: stripData.colA,
    colB: stripData.colB,
    colC: stripData.colC,
    imageUrl,
    hasImage,
    coverImagePath,
    imageFilePath: 'public/images/blog/' + stripData.topicSlug + '.jpg',
    photographerName,
    photoUrl
  }
}];

const topicData = $('Find First Pending Topic').first().json;
const sheetRow = {};
sheetRow[topicData.colA] = topicData.topic;
sheetRow[topicData.colB] = 'used';
if (topicData.colC) { sheetRow[topicData.colC] = DateTime.now().toFormat('yyyy-MM-dd'); }
return [{ json: { ...sheetRow, _topic: topicData.topic } }];
